const body = $json.body ?? {};
const marketInsights = body.marketInsights;
const sourceType = body.sourceType ?? 'unknown';
const executionContext = body.executionContext ?? {};
const projectName = executionContext.projectName?.trim() || body.marketInsights?.meta?.projectName || '未命名專案';

if (!marketInsights) {
  throw new Error('第二階段 workflow 需要 body.marketInsights。');
}

const insightText = typeof marketInsights === 'string'
  ? marketInsights
  : JSON.stringify(marketInsights, null, 2);

const stageConfigs = [
  { awarenessStage: 'Cold', stageTitle: '陌生客群 - 問題認知', conceptCount: 4, stageGoal: '讓受眾先意識到問題、感受到需求，願意停下來理解這個新切角。', conceptIdPrefix: 'C' },
  { awarenessStage: 'Warm', stageTitle: '溫受眾 - 方案比較', conceptCount: 4, stageGoal: '讓已經對問題有感的人理解你的方案為什麼值得考慮，並降低比較與猶豫。', conceptIdPrefix: 'W' },
  { awarenessStage: 'Hot', stageTitle: '熱受眾 - 臨門一腳', conceptCount: 4, stageGoal: '讓已經接近決策的人更願意採取行動，強化信任、急迫感與轉換理由。', conceptIdPrefix: 'H' }
];

return stageConfigs.map((config, index) => {
  const prompt = `你現在是一位頂尖的 Meta 廣告創意總監，深諳最新 Andromeda 演算法「真多樣化（Meaningful differences）」的核心邏輯。

以下 <market_insights> 標籤內，是我們在第一階段抓取並分析出的市場痛點、競品弱點、受眾語言與潛在切角。
請只針對 ${config.awarenessStage} 階段生成 ${config.conceptCount} 個完全不同、具備有意義差異的廣告 Concepts。

補充上下文：
- 專案名稱：${projectName}
- 洞察來源工作流：${sourceType}
- 執行階段：第二階段創意矩陣
- 本次點數成本：${executionContext.pointCost ?? 1} 點
- 認知階段：${config.awarenessStage}（${config.stageTitle}）
- 此階段目標：${config.stageGoal}
- 不可捏造不存在的產品功能、數據、客戶見證或市佔資訊。
- 如果資料不足，請縮短每個欄位字數，但仍要完整列出 ${config.conceptCount} 個 Concept。
- 禁止撰寫長篇前言，直接進入概念列表。

【矩陣要求】
1. 只生成 ${config.awarenessStage} 階段內容。
2. 共 ${config.conceptCount} 個 Concepts。
3. 每個 Concept 必須針對不同的次文化人群、心理渴望、使用情境或購買障礙。
4. 每個 Concept 的核心切入角度必須真正不同，禁止只是同一個概念換說法。
5. 每個欄位控制在 1 到 2 句內，保持精煉但可執行。
6. 嚴格遵守下方模板，所有 Concept 都必須使用完全相同的欄位名稱與順序，不可自行改名，不可省略欄位，不可使用 'H1:'、'W1:' 這類簡寫格式。

【輸出格式】
請使用 Markdown 格式輸出。
第一行固定輸出：## ${config.awarenessStage} - ${config.stageTitle}
之後每個 Concept 都必須嚴格使用以下模板：

### Concept ${config.conceptIdPrefix}1 - {名稱}
- Concept ID 與名稱: ${config.conceptIdPrefix}1 - {名稱}
- 認知階段: ${config.awarenessStage}
- 精準子人群與痛點: {內容}
- 核心切入點 (Big Idea): {內容}
- 建議廣告載體: {內容}
- 視覺與文案指引: {內容}

### Concept ${config.conceptIdPrefix}2 - {名稱}
- Concept ID 與名稱: ${config.conceptIdPrefix}2 - {名稱}
- 認知階段: ${config.awarenessStage}
- 精準子人群與痛點: {內容}
- 核心切入點 (Big Idea): {內容}
- 建議廣告載體: {內容}
- 視覺與文案指引: {內容}

依此類推直到 ${config.conceptIdPrefix}${config.conceptCount}。

【禁止事項】
- 不要輸出前言、結語、補充說明
- 不要使用粗體星號包欄位名稱
- 不要把欄位改成『Concept ID:』或『Concept ID 與名稱：』以外的寫法
- 不要把 Warm / Hot 階段改成段落敘事格式

<market_insights>
${insightText}
</market_insights>`;

  return {
    json: {
      workflowType: 'concept-matrix-batch',
      projectName,
      sourceType,
      executionContext: { ...executionContext, stage: 'stage_two', pointCost: executionContext.pointCost ?? 1 },
      marketInsights,
      insightText,
      awarenessStage: config.awarenessStage,
      stageTitle: config.stageTitle,
      conceptCount: config.conceptCount,
      conceptIdPrefix: config.conceptIdPrefix,
      batchIndex: index,
      prompt
    }
  };
});

const items = $input.all();
const originalItems = $('Code - Prepare Stage Prompts').all();

return items.map((item, index) => {
  const original = originalItems[index]?.json ?? {};
  const text = item.json.candidates?.[0]?.content?.parts?.map((part) => part.text).filter(Boolean).join('\n') ?? '未回傳內容。';

  return {
    json: {
      ...original,
      batchResult: text,
      raw: item.json
    }
  };
});

const items = $input.all().sort((a, b) => (a.json.batchIndex ?? 0) - (b.json.batchIndex ?? 0));

if (items.length === 0) {
  throw new Error('沒有可合併的第二階段批次結果。');
}

const normalizeBatchResult = (text, stageCode) => {
  let normalized = (text ?? '').trim();
  if (!normalized) return normalized;

  normalized = normalized.replace(/^\*\*資料限制說明：\*\*[\s\S]*?(?=^##\s|^###\s|^Concept|^### Concept|$)/m, '').trim();
  normalized = normalized.replace(/^#{1,6}\s*(Concept\s+)?([CWH]\d+)\s*[:：-]\s*/gm, '### Concept $2 - ');
  normalized = normalized.replace(/^-\s*\*\*Concept ID 與名稱\*\*\s*[:：]\s*/gm, '- Concept ID 與名稱: ');
  normalized = normalized.replace(/^-\s*\*\*認知階段\*\*\s*[:：]\s*/gm, '- 認知階段: ');
  normalized = normalized.replace(/^-\s*\*\*精準子人群與痛點\*\*\s*[:：]\s*/gm, '- 精準子人群與痛點: ');
  normalized = normalized.replace(/^-\s*\*\*核心切入點 \(Big Idea\)\*\*\s*[:：]\s*/gm, '- 核心切入點 (Big Idea): ');
  normalized = normalized.replace(/^-\s*\*\*建議廣告載體\*\*\s*[:：]\s*/gm, '- 建議廣告載體: ');
  normalized = normalized.replace(/^-\s*\*\*視覺與文案指引\*\*\s*[:：]\s*/gm, '- 視覺與文案指引: ');
  normalized = normalized.replace(/^Concept ID\s*[:：]\s*/gm, '- Concept ID 與名稱: ');
  normalized = normalized.replace(/^Concept ID 與名稱\s*[:：]\s*/gm, '- Concept ID 與名稱: ');
  normalized = normalized.replace(/^認知階段\s*[:：]\s*/gm, '- 認知階段: ');
  normalized = normalized.replace(/^精準子人群與痛點\s*[:：]\s*/gm, '- 精準子人群與痛點: ');
  normalized = normalized.replace(/^核心切入點 \(Big Idea\)\s*[:：]\s*/gm, '- 核心切入點 (Big Idea): ');
  normalized = normalized.replace(/^建議廣告載體\s*[:：]\s*/gm, '- 建議廣告載體: ');
  normalized = normalized.replace(/^視覺與文案指引\s*[:：]\s*/gm, '- 視覺與文案指引: ');
  normalized = normalized.replace(/^(C|W|H)(\d+)\s*[:：-]\s*/gm, '### Concept $1$2 - ');

  const stageTitleMap = {
    Cold: '陌生客群 - 問題認知',
    Warm: '溫受眾 - 方案比較',
    Hot: '熱受眾 - 臨門一腳'
  };

  if (!normalized.startsWith(`## ${stageCode} -`)) {
    normalized = `## ${stageCode} - ${stageTitleMap[stageCode] ?? ''}\n\n${normalized}`.trim();
  }

  return normalized;
};

const mergedSections = items.map((item) => normalizeBatchResult(item.json.batchResult, item.json.awarenessStage)).filter(Boolean);
const first = items[0].json;
const sourceType = first.sourceType ?? 'unknown';
const projectName = first.projectName ?? '未命名專案';
const pointCost = first.executionContext?.pointCost ?? 1;
const finalResult = `# Meta 廣告創意 Concepts (共 12 個)\n\n${mergedSections.join('\n\n---\n\n')}\n\n## 最值得優先測試的前 3 個 Concept\n- 請先檢查上方 Cold / Warm / Hot 三組概念，優先挑選最貼近你目前投放目標與素材能力的 3 個方向進行測試。`;

return [{ json: { ok: true, type: 'concept-matrix', result: finalResult, meta: { projectName, sourceType, stage: 'stage_two', pointCost, generatedAt: new Date().toISOString(), batchCount: items.length }, batches: items.map((item) => ({ awarenessStage: item.json.awarenessStage, stageTitle: item.json.stageTitle, batchResult: normalizeBatchResult(item.json.batchResult, item.json.awarenessStage) })) } }];
